// ── alaric_sprites.js — sword sprite for Alaric Filo Dorado skin ──
'use strict';

const AlaricSprites = (() => {
    const img = new Image();
    img.src = 'data:image/png;base64,';
    // TIP_ALIGN: rotation to apply so the sword TIP points along +X axis
    // Tip is at ~135° from center in the image, so we rotate -135° to align
    const TIP_ALIGN = -2.364; // radians
    return {
        get sword()    { return img; },
        get ready()    { return img.complete && img.naturalWidth > 0; },
        TIP_ALIGN,
    };
})();
